mapper.select:
SELECT COUNT(*) FROM hm_query.dim_product

    AND product_status = 'PUBLISHED'

        AND featured = #{featured}


        AND product_name ILIKE CONCAT('%', #{name}, '%')


        AND product_id = #{productId}


        AND brand ILIKE CONCAT('%', #{brand}, '%')


        AND category_id = #{categoryId}


        AND (product_name ILIKE CONCAT('%', #{q}, '%') OR brand ILIKE CONCAT('%', #{q}, '%') OR description ILIKE CONCAT('%', #{q}, '%'))

SELECT p.product_id as ID, p.product_id as product_id, p.product_name as name, p.description as description, p.brand as brand, p.primary_image_url as image_url, p.base_price as price, p.selling_price as selling_price, p.featured as featured, CASE WHEN p.product_status = 'PUBLISHED' THEN true ELSE false END as active, 0 as display_order, CASE WHEN p.stock_status != 'OUT_OF_STOCK' THEN true ELSE false END as in_stock, p.total_available_qty as available_qty, p.avg_rating as average_rating, p.review_count as review_count, p.category_id as category_id, p.category_name as category_name FROM hm_query.dim_product p
AND p.product_status = 'PUBLISHED'
AND p.featured = #{featured}
AND p.product_name ILIKE CONCAT('%', #{name}, '%')
AND p.product_id = #{productId}
AND p.brand ILIKE CONCAT('%', #{brand}, '%')
AND p.category_id = #{categoryId}
AND (p.product_name ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%') OR p.description ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.dim_product


        AND featured = #{featured}


        AND CASE WHEN #{active} = true THEN product_status = 'PUBLISHED' ELSE product_status != 'PUBLISHED' END


        AND product_name ILIKE CONCAT('%', #{name}, '%')


        AND product_id = #{productId}


        AND (product_name ILIKE CONCAT('%', #{q}, '%') OR brand ILIKE CONCAT('%', #{q}, '%'))

SELECT p.product_id as ID, p.product_id as product_id, p.product_name as name, p.description as description, p.brand as brand, p.primary_image_url as image_url, p.base_price as price, p.selling_price as selling_price, p.featured as featured, CASE WHEN p.product_status = 'PUBLISHED' THEN true ELSE false END as active, 0 as display_order, CASE WHEN p.stock_status != 'OUT_OF_STOCK' THEN true ELSE false END as in_stock, p.total_available_qty as available_qty, p.avg_rating as average_rating, p.review_count as review_count, p.category_id as category_id, p.category_name as category_name FROM hm_query.dim_product p
AND p.featured = #{featured}
AND CASE WHEN #{active} = true THEN p.product_status = 'PUBLISHED' ELSE p.product_status != 'PUBLISHED' END
AND p.product_name ILIKE CONCAT('%', #{name}, '%')
AND p.product_id = #{productId}
AND (p.product_name ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT DISTINCT p.product_id as ID, p.product_id as product_id, p.product_name as name, p.description as description, p.brand as brand, p.primary_image_url as image_url, p.base_price as price, p.selling_price as selling_price, p.featured as featured, CASE WHEN p.product_status = 'PUBLISHED' THEN true ELSE false END as active, 0 as display_order, CASE WHEN p.stock_status != 'OUT_OF_STOCK' THEN true ELSE false END as in_stock, p.total_available_qty as available_qty, p.avg_rating as average_rating, p.review_count as review_count, p.category_id as category_id, p.category_name as category_name FROM hm_query.dim_product p LEFT JOIN hm_query.product_tag_flat pt ON p.product_id = pt.product_id
AND pt.tag IN
#{item}
AND CASE WHEN #{active} = true THEN p.product_status = 'PUBLISHED' ELSE p.product_status != 'PUBLISHED' END
AND (p.product_name ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.dim_product p


        AND p.category_id = #{categoryId}


        AND CASE WHEN #{active} = true THEN p.product_status = 'PUBLISHED' ELSE p.product_status != 'PUBLISHED' END


        AND p.product_name ILIKE CONCAT('%', #{name}, '%')


        AND p.product_id = #{productId}


        AND (p.product_name ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%') OR p.description ILIKE CONCAT('%', #{q}, '%'))

SELECT p.product_id as ID, p.product_id as product_id, p.product_name as name, p.description as description, p.brand as brand, p.primary_image_url as image_url, p.base_price as price, p.selling_price as selling_price, p.featured as featured, CASE WHEN p.product_status = 'PUBLISHED' THEN true ELSE false END as active, 0 as display_order, CASE WHEN p.stock_status != 'OUT_OF_STOCK' THEN true ELSE false END as in_stock, p.total_available_qty as available_qty, p.avg_rating as average_rating, p.review_count as review_count, p.category_id as category_id, p.category_name as category_name FROM hm_query.dim_product p
AND p.category_id = #{categoryId}
AND CASE WHEN #{active} = true THEN p.product_status = 'PUBLISHED' ELSE p.product_status != 'PUBLISHED' END
AND p.product_name ILIKE CONCAT('%', #{name}, '%')
AND p.product_id = #{productId}
AND (p.product_name ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%') OR p.description ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
